110:                               const Network::Connection& connection) override;
111: 
112:   private:
113:     struct ConnectionInfo {
114:       Envoy::Http::ConnectionPool::Instance* pool_; // Not a ref to allow assignment in remove().
115:       const Network::Connection* connection_;       // Not a ref to allow assignment in remove().
116:     };
117:     struct LookupKey {
118:       const std::vector<uint8_t> hash_key_;
119:       const Network::Address::Instance& peer_address_;
120:       bool operator==(const LookupKey& rhs) const {
121:         return std::tie(hash_key_, peer_address_) == std::tie(rhs.hash_key_, rhs.peer_address_);
122:       }
123:     };
124:     struct LookupKeyHash {
125:       size_t operator()(const LookupKey& lookup_key) const {
126:         return std::hash<std::string>{}(lookup_key.peer_address_.asString());
127:       }
128:     };
129: 
130:     absl::flat_hash_map<LookupKey, std::vector<ConnectionInfo>, LookupKeyHash> connection_info_map_;
131: 
132:     const Cluster& cluster_;
133:   };
