221: // checkIdle run in the main thread.
222: bool Cluster::ClusterInfo::checkIdle() {
223:   ASSERT(parent_.main_thread_dispatcher_.isThreadSafe());
224: 
225:   const std::chrono::steady_clock::duration now_duration =
226:       parent_.main_thread_dispatcher_.timeSource().monotonicTime().time_since_epoch();
227:   auto last_used_time = last_used_time_.load();
228:   ENVOY_LOG(debug, "cluster='{}' TTL check: now={} last_used={} TTL {}", cluster_name_,
229:             now_duration.count(), last_used_time.count(), parent_.sub_cluster_ttl_.count());
230: 
231:   if ((now_duration - last_used_time) > parent_.sub_cluster_ttl_) {
232:     ENVOY_LOG(debug, "cluster='{}' TTL expired", cluster_name_);
233:     return true;
234:   }
235:   return false;
236: }
