310: void Cluster::updatePriorityState(const Upstream::HostVector& hosts_added,
311:                                   const Upstream::HostVector& hosts_removed) {
312:   Upstream::PriorityStateManager priority_state_manager(*this, local_info_, nullptr);
313:   priority_state_manager.initializePriorityFor(dummy_locality_lb_endpoint_);
314:   {
315:     absl::ReaderMutexLock lock{&host_map_lock_};
316:     for (const auto& host : host_map_) {
317:       priority_state_manager.registerHostForPriority(host.second.logical_host_,
318:                                                      dummy_locality_lb_endpoint_);
319:     }
320:   }
321:   priority_state_manager.updateClusterPrioritySet(
322:       0, std::move(priority_state_manager.priorityState()[0].first), hosts_added, hosts_removed,
323:       absl::nullopt, absl::nullopt, absl::nullopt);
324: }
