409: absl::optional<Upstream::SelectedPoolAndConnection>
410: Cluster::LoadBalancer::selectExistingConnection(Upstream::LoadBalancerContext* /*context*/,
411:                                                 const Upstream::Host& host,
412:                                                 std::vector<uint8_t>& hash_key) {
413:   const std::string& hostname = host.hostname();
414:   if (hostname.empty()) {
415:     return absl::nullopt;
416:   }
417: 
418:   LookupKey key = {hash_key, *host.address()};
419:   auto it = connection_info_map_.find(key);
420:   if (it == connection_info_map_.end()) {
421:     return absl::nullopt;
422:   }
423: 
424:   for (auto& info : it->second) {
425:     Envoy::Ssl::ConnectionInfoConstSharedPtr ssl = info.connection_->ssl();
426:     ASSERT(ssl);
