771: void PrioritySetImpl::batchHostUpdate(BatchUpdateCb& callback) {
772:   BatchUpdateScope scope(*this);
773: 
774:   // We wrap the update call with a lambda that tracks all the hosts that have been added/removed.
775:   callback.batchUpdate(scope);
776: 
777:   // Now that all the updates have been complete, we can compute the diff.
778:   HostVector net_hosts_added = filterHosts(scope.all_hosts_added_, scope.all_hosts_removed_);
779:   HostVector net_hosts_removed = filterHosts(scope.all_hosts_removed_, scope.all_hosts_added_);
780: 
781:   runUpdateCallbacks(net_hosts_added, net_hosts_removed);
782: }
