821: HostMapConstSharedPtr MainPrioritySetImpl::crossPriorityHostMap() const {
822:   // Check if the host set in the main thread PrioritySet has been updated.
823:   if (mutable_cross_priority_host_map_ != nullptr) {
824:     const_cross_priority_host_map_ = std::move(mutable_cross_priority_host_map_);
825:     ASSERT(mutable_cross_priority_host_map_ == nullptr);
