830: void MainPrioritySetImpl::updateCrossPriorityHostMap(const HostVector& hosts_added,
831:                                                      const HostVector& hosts_removed) {
832:   if (hosts_added.empty() && hosts_removed.empty()) {
833:     // No new hosts have been added and no old hosts have been removed.
834:     return;
835:   }
836: 
837:   // Since read_only_all_host_map_ may be shared by multiple threads, when the host set changes,
838:   // we cannot directly modify read_only_all_host_map_.
839:   if (mutable_cross_priority_host_map_ == nullptr) {
840:     // Copy old read only host map to mutable host map.
841:     mutable_cross_priority_host_map_ = std::make_shared<HostMap>(*const_cross_priority_host_map_);
842:   }
843: 
844:   for (const auto& host : hosts_removed) {
845:     mutable_cross_priority_host_map_->erase(addressToString(host->address()));
846:   }
847: 
848:   for (const auto& host : hosts_added) {
849:     mutable_cross_priority_host_map_->insert({addressToString(host->address()), host});
850:   }
851: }
